                Strongconnect(w);
                low[v] = Math.Min(low[v], low[w]);
            }
            else if (onStack[w])
            {
                low[v] = Math.Min(low[v], disc[w]);
            }
        }

        if (low[v] == disc[v])
        {
            sccCount++;
            while (true)
            {
                int w = stack.Pop();
                onStack[w] = false;
                if (w == v) break;
            }
        }
    }
}

